  const [touched, setTouched] = useState<Record<string, boolean>>({});
  const errors = useMemo(() => Object.fromEntries(fields.map(f => [f.name, f.required && !values[f.name]?.trim() ? `${f.label} is required` : null])), [fields, values]);
  const invalid = Object.values(errors).some(Boolean);
  return <KeyboardAvoidingView behavior={Platform.OS === 'ios' ? 'padding' : undefined} style={styles.wrap}>{fields.map((field) => <View key={field.name} style={styles.field}><Text style={styles.label}>{field.label}</Text><TextInput value={values[field.name] ?? ''} onChangeText={(text) => setValues(v => ({...v, [field.name]: text}))} onBlur={() => setTouched(t => ({...t, [field.name]: true}))} keyboardType={field.keyboardType ?? 'default'} accessibilityLabel={field.label} accessibilityHint={errors[field.name] || undefined} style={[styles.input, touched[field.name] && errors[field.name] && styles.inputError]} />{touched[field.name] && errors[field.name] ? <Text accessibilityLiveRegion="polite" style={styles.error}>{errors[field.name]}</Text> : null}</View>)}<Pressable disabled={invalid} onPress={() => onSubmit(values)} accessibilityRole="button" style={[styles.submit, invalid && styles.disabled]}><Text style={styles.submitText}>Save</Text></Pressable></KeyboardAvoidingView>;
}
