import { NativeModules, Platform } from 'react-native';
import * as Notifications from 'expo-notifications';

const { LiveActivityModule } = NativeModules as { LiveActivityModule?: { start(id: string, payload: object): Promise<void>; update(id: string, payload: object): Promise<void>; end(id: string): Promise<void> } };

export async function startLongRunningTaskActivity(task: { id: string; title: string; progress: number }) {
  if (Platform.OS === 'ios' && LiveActivityModule) {
    await LiveActivityModule.start(task.id, { title: task.title, progress: task.progress });
    return;
  }
  await Notifications.scheduleNotificationAsync({ content: { title: task.title, body: `${Math.round(task.progress * 100)}% complete` }, trigger: null });
}

export async function updateLongRunningTaskActivity(task: { id: string; title: string; progress: number; done?: boolean }) {
  if (Platform.OS === 'ios' && LiveActivityModule) {
    task.done ? await LiveActivityModule.end(task.id) : await LiveActivityModule.update(task.id, task);
  }
}
